import{_ as r,o as i,c as l,ai as n}from"./chunks/framework.CaiDwmc7.js";const b=JSON.parse('{"title":"Java/Spring 生态","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/backend/java-spring.md","filePath":"tech-system/backend/java-spring.md"}'),t={name:"tech-system/backend/java-spring.md"};function s(e,a,o,g,h,d){return i(),l("div",null,[...a[0]||(a[0]=[n('<h1 id="java-spring-生态" tabindex="-1">Java/Spring 生态 <a class="header-anchor" href="#java-spring-生态" aria-label="Permalink to “Java/Spring 生态”">​</a></h1><p>Java/Spring 生态是企业级后端开发的主流技术栈，涵盖从基础语法到微服务架构的完整解决方案。</p><h2 id="java-基础" tabindex="-1">Java 基础 <a class="header-anchor" href="#java-基础" aria-label="Permalink to “Java 基础”">​</a></h2><h3 id="jvm-虚拟机" tabindex="-1">JVM 虚拟机 <a class="header-anchor" href="#jvm-虚拟机" aria-label="Permalink to “JVM 虚拟机”">​</a></h3><ul><li><strong>JVM 内存模型</strong>: 堆、栈、方法区、程序计数器</li><li><strong>垃圾回收机制</strong>: GC算法、垃圾收集器选择、分代回收</li><li><strong>JVM 调优</strong>: 参数配置、性能监控、内存分析</li><li><strong>字节码</strong>: Class文件结构、字节码指令、JIT编译</li></ul><h3 id="java-并发编程" tabindex="-1">Java 并发编程 <a class="header-anchor" href="#java-并发编程" aria-label="Permalink to “Java 并发编程”">​</a></h3><ul><li><strong>线程基础</strong>: 线程创建、生命周期、线程安全</li><li><strong>并发工具类</strong>: Atomic、Lock、Semaphore、CountDownLatch</li><li><strong>线程池</strong>: Executor框架、线程池参数配置</li><li><strong>并发容器</strong>: ConcurrentHashMap、BlockingQueue</li></ul><h3 id="java-新特性" tabindex="-1">Java 新特性 <a class="header-anchor" href="#java-新特性" aria-label="Permalink to “Java 新特性”">​</a></h3><ul><li><strong>Java 8</strong>: Lambda表达式、Stream API、Optional、新的日期API</li><li><strong>Java 11</strong>: var关键字、字符串API增强、Epsilon GC</li><li><strong>Java 17</strong>: Sealed Classes、Pattern Matching、Records</li></ul><h2 id="spring-框架" tabindex="-1">Spring 框架 <a class="header-anchor" href="#spring-框架" aria-label="Permalink to “Spring 框架”">​</a></h2><h3 id="spring-core" tabindex="-1">Spring Core <a class="header-anchor" href="#spring-core" aria-label="Permalink to “Spring Core”">​</a></h3><ul><li><strong>IoC 容器</strong>: Bean生命周期、依赖注入、Bean作用域</li><li><strong>AOP 面向切面</strong>: 切点表达式、通知类型、代理机制</li><li><strong>事件机制</strong>: ApplicationEvent、事件监听器</li></ul><h3 id="spring-boot" tabindex="-1">Spring Boot <a class="header-anchor" href="#spring-boot" aria-label="Permalink to “Spring Boot”">​</a></h3><ul><li><strong>自动配置</strong>: @EnableAutoConfiguration、条件注解</li><li><strong>Starter</strong>: 官方Starter、自定义Starter开发</li><li><strong>配置管理</strong>: application.yml、@ConfigurationProperties</li><li><strong>Actuator</strong>: 健康检查、指标监控、环境信息</li></ul><h3 id="spring-data" tabindex="-1">Spring Data <a class="header-anchor" href="#spring-data" aria-label="Permalink to “Spring Data”">​</a></h3><ul><li><strong>JPA/Hibernate</strong>: 实体映射、查询方法、事务管理</li><li><strong>MongoDB</strong>: 文档映射、查询操作、索引管理</li><li><strong>Redis</strong>: 缓存抽象、数据类型操作</li><li><strong>Elasticsearch</strong>: 搜索抽象、索引管理</li></ul><h2 id="微服务架构" tabindex="-1">微服务架构 <a class="header-anchor" href="#微服务架构" aria-label="Permalink to “微服务架构”">​</a></h2><h3 id="服务拆分" tabindex="-1">服务拆分 <a class="header-anchor" href="#服务拆分" aria-label="Permalink to “服务拆分”">​</a></h3><ul><li><strong>DDD 领域驱动设计</strong>: 限界上下文、聚合、实体</li><li><strong>服务边界</strong>: 康威定律、业务边界识别</li><li><strong>数据一致性</strong>: 分布式事务、Saga模式、事件溯源</li></ul><h3 id="服务通信" tabindex="-1">服务通信 <a class="header-anchor" href="#服务通信" aria-label="Permalink to “服务通信”">​</a></h3><ul><li><strong>RESTful API</strong>: HTTP方法、状态码、HATEOAS</li><li><strong>RPC 框架</strong>: Dubbo、gRPC、Thrift</li><li><strong>消息队列</strong>: RabbitMQ、Kafka、RocketMQ</li><li><strong>服务网格</strong>: Istio、Linkerd</li></ul><h3 id="服务治理" tabindex="-1">服务治理 <a class="header-anchor" href="#服务治理" aria-label="Permalink to “服务治理”">​</a></h3><ul><li><strong>服务发现与实例健康</strong>: 注册中心、心跳、实例上下线</li><li><strong>负载均衡与调用</strong>: 路由、超时、重试与幂等</li><li><strong>熔断与限流</strong>: 舱壁、熔断降级、限流</li><li><strong>API 网关</strong>: 统一入口、路由、鉴权与观测</li></ul><h2 id="数据库集成" tabindex="-1">数据库集成 <a class="header-anchor" href="#数据库集成" aria-label="Permalink to “数据库集成”">​</a></h2><h3 id="mysql" tabindex="-1">MySQL <a class="header-anchor" href="#mysql" aria-label="Permalink to “MySQL”">​</a></h3><ul><li><strong>连接池</strong>: HikariCP、Druid配置优化</li><li><strong>ORM</strong>: JPA、MyBatis、MyBatis-Plus</li><li><strong>分库分表</strong>: ShardingSphere、MyCat</li><li><strong>读写分离</strong>: 主从复制、代理层</li></ul><h3 id="redis" tabindex="-1">Redis <a class="header-anchor" href="#redis" aria-label="Permalink to “Redis”">​</a></h3><ul><li><strong>数据类型</strong>: String、Hash、List、Set、ZSet</li><li><strong>持久化</strong>: RDB、AOF、混合持久化</li><li><strong>集群</strong>: 主从复制、哨兵模式、Cluster</li><li><strong>缓存策略</strong>: 缓存穿透、缓存雪崩、缓存击穿</li></ul><h3 id="elasticsearch" tabindex="-1">Elasticsearch <a class="header-anchor" href="#elasticsearch" aria-label="Permalink to “Elasticsearch”">​</a></h3><ul><li><strong>索引管理</strong>: 映射、设置、分词器</li><li><strong>查询DSL</strong>: 结构化查询、全文检索</li><li><strong>聚合分析</strong>: 指标聚合、桶聚合</li><li><strong>集群管理</strong>: 节点角色、分片、副本</li></ul><h2 id="安全与认证" tabindex="-1">安全与认证 <a class="header-anchor" href="#安全与认证" aria-label="Permalink to “安全与认证”">​</a></h2><h3 id="spring-security" tabindex="-1">Spring Security <a class="header-anchor" href="#spring-security" aria-label="Permalink to “Spring Security”">​</a></h3><ul><li><strong>认证方式</strong>: 表单登录、HTTP Basic、OAuth2</li><li><strong>授权模型</strong>: 基于角色的访问控制、方法级安全</li><li><strong>JWT</strong>: 无状态认证、Token刷新</li><li><strong>SSO</strong>: 单点登录实现</li></ul><h3 id="oauth2" tabindex="-1">OAuth2 <a class="header-anchor" href="#oauth2" aria-label="Permalink to “OAuth2”">​</a></h3><ul><li><strong>授权码模式</strong>: 标准OAuth2流程</li><li><strong>密码模式</strong>: 资源所有者密码凭据</li><li><strong>客户端模式</strong>: 客户端凭据授权</li><li><strong>简化模式</strong>: 隐式授权</li></ul><h2 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to “性能优化”">​</a></h2><h3 id="jvm-调优" tabindex="-1">JVM 调优 <a class="header-anchor" href="#jvm-调优" aria-label="Permalink to “JVM 调优”">​</a></h3><ul><li><strong>内存调优</strong>: 堆大小、GC参数、新生代比例</li><li><strong>GC 调优</strong>: 垃圾收集器选择、GC日志分析</li><li><strong>JIT 编译</strong>: 编译阈值、代码缓存</li></ul><h3 id="应用优化" tabindex="-1">应用优化 <a class="header-anchor" href="#应用优化" aria-label="Permalink to “应用优化”">​</a></h3><ul><li><strong>缓存策略</strong>: 多级缓存、本地缓存、分布式缓存</li><li><strong>异步处理</strong>: @Async、CompletableFuture、消息队列</li><li><strong>连接池</strong>: 数据库连接池、HTTP连接池</li><li><strong>监控告警</strong>: JVM监控、应用指标、APM</li></ul><h2 id="测试" tabindex="-1">测试 <a class="header-anchor" href="#测试" aria-label="Permalink to “测试”">​</a></h2><h3 id="单元测试" tabindex="-1">单元测试 <a class="header-anchor" href="#单元测试" aria-label="Permalink to “单元测试”">​</a></h3><ul><li><strong>JUnit 5</strong>: 测试生命周期、参数化测试、动态测试</li><li><strong>Mockito</strong>: 模拟对象、行为验证、参数匹配</li><li><strong>Testcontainers</strong>: 集成测试容器化</li></ul><h3 id="集成测试" tabindex="-1">集成测试 <a class="header-anchor" href="#集成测试" aria-label="Permalink to “集成测试”">​</a></h3><ul><li><strong>Spring Test</strong>: @SpringBootTest、测试切片</li><li><strong>REST Assured</strong>: REST API测试</li><li><strong>WireMock</strong>: HTTP服务模拟</li></ul><h2 id="部署与运维" tabindex="-1">部署与运维 <a class="header-anchor" href="#部署与运维" aria-label="Permalink to “部署与运维”">​</a></h2><h3 id="容器化" tabindex="-1">容器化 <a class="header-anchor" href="#容器化" aria-label="Permalink to “容器化”">​</a></h3><ul><li><strong>Docker</strong>: 多阶段构建、镜像优化</li><li><strong>Docker Compose</strong>: 多服务编排</li><li><strong>Kubernetes</strong>: Deployment、Service、ConfigMap</li></ul><h3 id="ci-cd" tabindex="-1">CI/CD <a class="header-anchor" href="#ci-cd" aria-label="Permalink to “CI/CD”">​</a></h3><ul><li><strong>Jenkins</strong>: Pipeline as Code、插件生态</li><li><strong>GitLab CI</strong>: .gitlab-ci.yml、流水线设计</li><li><strong>GitHub Actions</strong>: 工作流模板、Actions市场</li></ul><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to “最佳实践”">​</a></h2><h3 id="代码规范" tabindex="-1">代码规范 <a class="header-anchor" href="#代码规范" aria-label="Permalink to “代码规范”">​</a></h3><ul><li><strong>命名规范</strong>: 包命名、类命名、方法命名</li><li><strong>代码结构</strong>: 分层架构、职责分离</li><li><strong>异常处理</strong>: 异常分类、异常链</li></ul><h3 id="设计模式" tabindex="-1">设计模式 <a class="header-anchor" href="#设计模式" aria-label="Permalink to “设计模式”">​</a></h3><ul><li><strong>创建型模式</strong>: 工厂模式、单例模式、建造者模式</li><li><strong>结构型模式</strong>: 适配器模式、装饰器模式、代理模式</li><li><strong>行为型模式</strong>: 观察者模式、策略模式、模板方法</li></ul><h3 id="架构模式" tabindex="-1">架构模式 <a class="header-anchor" href="#架构模式" aria-label="Permalink to “架构模式”">​</a></h3><ul><li><strong>分层架构</strong>: 表示层、业务层、数据访问层</li><li><strong>领域驱动设计</strong>: 领域模型、应用服务、基础设施</li><li><strong>CQRS</strong>: 命令查询职责分离、事件溯源</li></ul>',57)])])}const u=r(t,[["render",s]]);export{b as __pageData,u as default};
